function fileToBase64(file) {
  return new Promise((res, rej) => {
    const r = new FileReader();
    r.onload = () => res(r.result.split(",")[1]);
    r.onerror = () => rej(new Error("Не удалось прочитать файл"));
    r.readAsDataURL(file);
  });
}

async function parseFile(file) {
  const name = file.name;
  const ext = name.split(".").pop().toLowerCase();
  const id = Math.random().toString(36).slice(2);

  if (["png", "jpg", "jpeg", "gif", "webp", "bmp"].includes(ext)) {
    const b64 = await fileToBase64(file);
    const mt = ext === "jpg" ? "image/jpeg" : `image/${ext}`;
    return { id, name, kind: "image", mediaType: mt, data: b64, preview: `data:${mt};base64,${b64}` };
  }
  if (["xlsx", "xls", "xlsm", "csv", "tsv"].includes(ext)) {
    const buf = await file.arrayBuffer();
    const wb = XLSX.read(buf, { type: "array" });
    let out = "";
    wb.SheetNames.forEach((s) => { out += `# Лист: ${s}\n${XLSX.utils.sheet_to_csv(wb.Sheets[s])}\n\n`; });
    return { id, name, kind: "table", text: out.trim() };
  }
  if (ext === "docx") {
    const buf = await file.arrayBuffer();
    const { value } = await mammoth.extractRawText({ arrayBuffer: buf });
    return { id, name, kind: "doc", text: value.trim() };
  }
  if (["txt", "md", "json"].includes(ext)) {
    return { id, name, kind: "text", text: (await file.text()).trim() };
  }
  if (ext === "doc") throw new Error(".doc не читается в браузере — пересохрани как .docx");
  throw new Error(`Формат .${ext} не поддерживается`);
}

