async function callClaude({ system, userContent, user }) {
  const messages = userContent
    ? [{ role: "user", content: userContent }]
    : [{ role: "user", content: user }];
  // Запрос идёт на наш backend-прокси, а не напрямую в Anthropic —
  // API-ключ хранится на сервере и не попадает в браузер.
  const resp = await fetch("/api/generate", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ model: MODEL, max_tokens: 1500, system, messages }),
  });
  const data = await resp.json();
  if (!resp.ok || !Array.isArray(data.content)) {
    const msg = data?.error?.message || data?.error || `Сервер вернул ${resp.status}`;
    throw new Error(msg);
  }
  const text = data.content.filter((b) => b.type === "text").map((b) => b.text).join("\n");
  return JSON.parse(text.replace(/```json/g, "").replace(/```/g, "").trim());
}

